column2:
SELECT l.level
FROM npcyf_schema."LOCATION_RESERVOIR_LEVEL" AS l
WHERE l.reservoir_level_recorded_date = DATE '2010-01-01';

SELECT EXISTS (
  SELECT 1
  FROM npcyf_schema."CROP"
  WHERE crop_name ILIKE '%wheat%'
);

SELECT crop_id
FROM npcyf_schema."CROP"
WHERE crop_name ILIKE '%rice%';

SELECT *
FROM npcyf_schema."CROP"
ORDER BY crop_name;

SELECT t.temperature_value
FROM npcyf_schema."LOCATION_TEMPERATURE" AS t
WHERE t.temperature_data_collection_id = 1;
